using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.Json;
using System.Text.RegularExpressions;
using Microsoft.Extensions.AI;
using OpenAI;

// ---------------------------------------------------------------------------
// Configuration
// ---------------------------------------------------------------------------
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o";

Console.WriteLine("🔬 Research Agent");
Console.WriteLine($"   Model : {model}");
Console.WriteLine();
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

// ---------------------------------------------------------------------------
// Build AI client with automatic function-calling support
// ---------------------------------------------------------------------------
using var httpClient = new HttpClient();
httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");
httpClient.Timeout = TimeSpan.FromSeconds(30);

IChatClient client = new ChatClientBuilder(
        new OpenAIClient(apiKey).GetChatClient(model).AsIChatClient())
    .UseFunctionInvocation()
    .Build();

// ---------------------------------------------------------------------------
// Shared state – research notes
// ---------------------------------------------------------------------------
var notes = new List<ResearchNote>();

// ---------------------------------------------------------------------------
// Tool definitions
// ---------------------------------------------------------------------------

[Description("Search the web for information on a query. Returns titles, snippets, and URLs.")]
async Task<string> SearchWeb(
    [Description("The search query")] string query)
{
    Console.WriteLine($"  🔍 Searching: \"{query}\"");
    try
    {
        var url = $"https://api.duckduckgo.com/?q={Uri.EscapeDataString(query)}"
                + "&format=json&no_html=1&skip_disambig=1";
        var json = await httpClient.GetStringAsync(url);
        using var doc = JsonDocument.Parse(json);
        var root = doc.RootElement;

        var sb = new StringBuilder();

        var abstractText = root.GetProperty("AbstractText").GetString();
        var abstractUrl  = root.GetProperty("AbstractURL").GetString();
        if (!string.IsNullOrEmpty(abstractText))
        {
            sb.AppendLine($"## Summary");
            sb.AppendLine(abstractText);
            sb.AppendLine($"Source: {abstractUrl}");
            sb.AppendLine();
        }

        if (root.TryGetProperty("RelatedTopics", out var topics))
        {
            var count = 0;
            foreach (var item in topics.EnumerateArray())
            {
                if (count >= 8) break;
                if (item.TryGetProperty("Text", out var text) &&
                    item.TryGetProperty("FirstURL", out var itemUrl))
                {
                    sb.AppendLine($"- {text.GetString()}");
                    sb.AppendLine($"  URL: {itemUrl.GetString()}");
                    count++;
                }
            }
        }

        var result = sb.ToString();
        return string.IsNullOrWhiteSpace(result)
            ? "No results found. Try a different or more specific query."
            : result;
    }
    catch (Exception ex)
    {
        return $"Search failed: {ex.Message}";
    }
}

[Description("Fetch and read the text content of a web page at the given URL.")]
async Task<string> FetchWebPage(
    [Description("The full URL to fetch")] string url)
{
    Console.WriteLine($"  🌐 Fetching: {url}");
    try
    {
        var html = await httpClient.GetStringAsync(url);

        // Rough HTML → plain-text conversion
        var text = Regex.Replace(html, @"<script[^>]*>[\s\S]*?</script>", " ",
            RegexOptions.IgnoreCase);
        text = Regex.Replace(text, @"<style[^>]*>[\s\S]*?</style>", " ",
            RegexOptions.IgnoreCase);
        text = Regex.Replace(text, @"<[^>]+>", " ");
        text = WebUtility.HtmlDecode(text);
        text = Regex.Replace(text, @"\s+", " ").Trim();

        const int maxLen = 4000;
        if (text.Length > maxLen)
            text = text[..maxLen] + "\n... [truncated]";

        return string.IsNullOrWhiteSpace(text)
            ? "Could not extract content from the page."
            : text;
    }
    catch (Exception ex)
    {
        return $"Failed to fetch page: {ex.Message}";
    }
}

[Description("Save a research note to remember important findings.")]
string TakeNote(
    [Description("Short title for the note")] string title,
    [Description("Detailed content / key findings")] string content)
{
    Console.WriteLine($"  📝 Note saved: \"{title}\"");
    notes.Add(new ResearchNote(title, content));
    return $"Note saved: \"{title}\" ({notes.Count} total)";
}

[Description("Retrieve all research notes taken so far.")]
string GetNotes()
{
    if (notes.Count == 0) return "No notes have been taken yet.";

    var sb = new StringBuilder();
    for (var i = 0; i < notes.Count; i++)
    {
        sb.AppendLine($"### Note {i + 1}: {notes[i].Title}");
        sb.AppendLine(notes[i].Content);
        sb.AppendLine();
    }
    return sb.ToString();
}

// ---------------------------------------------------------------------------
// Register tools and build chat options
// ---------------------------------------------------------------------------
var chatOptions = new ChatOptions
{
    Tools =
    [
        AIFunctionFactory.Create(SearchWeb),
        AIFunctionFactory.Create(FetchWebPage),
        AIFunctionFactory.Create(TakeNote),
        AIFunctionFactory.Create(GetNotes),
    ]
};

var systemPrompt = """
    You are a thorough research agent. Your goal is to research the user's topic
    by searching the web, reading relevant pages, and taking structured notes.

    Follow this workflow:
    1. Search the web with several relevant queries to explore the topic broadly.
    2. Fetch promising web pages from the search results for deeper reading.
    3. Take notes on the most important findings as you go (at least 3 notes).
    4. After gathering enough information, review your notes and write a
       comprehensive, well-organized summary with citations.

    Be thorough but focused. Always cite your sources.
    """;

var messages = new List<ChatMessage>
{
    new(ChatRole.System, systemPrompt),
    new(ChatRole.User, $"Please research the following topic: {topic}")
};

// ---------------------------------------------------------------------------
// Run the agent loop
// ---------------------------------------------------------------------------
Console.WriteLine();
Console.WriteLine($"Researching: \"{topic}\"");
Console.WriteLine(new string('─', 60));

var response = await client.GetResponseAsync(messages, chatOptions);

Console.WriteLine(new string('─', 60));
Console.WriteLine();

// Print the final assistant response
foreach (var msg in response.Messages)
{
    if (msg.Role == ChatRole.Assistant && msg.Text is { Length: > 0 })
    {
        Console.WriteLine(msg.Text);
    }
}

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------
record ResearchNote(string Title, string Content);

